import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => { if (isLoggedIn) fetchData(); }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Wrong Password!");
  };

  // अपडेट करण्याचे फंक्शन (मायनस व्हॅल्यू फिक्स करण्यासाठी बदल)
  const handleUpdate = async (id, currentStatus, currentProgress) => {
    // व्हॅल्यू 0 पेक्षा कमी असेल तर 0 करा, आणि 100 पेक्षा जास्त असेल तर 100 करा
    let fixedProgress = Math.max(0, Math.min(100, currentProgress));

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, { 
        status: currentStatus, 
        progress: fixedProgress 
      });
      alert("Project Updated Successfully!");
      fetchData();
    } catch (err) { console.error(err); }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure?")) {
      await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
      fetchData();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container py-5 text-center mt-5">
        <div className="card shadow p-4 mx-auto border-0" style={{ maxWidth: '400px' }}>
          <h3>Admin Dashboard</h3>
          <form onSubmit={handleLogin}>
            <input type="password" placeholder="Password" className="form-control mb-3 text-center" value={password} onChange={(e) => setPassword(e.target.value)} required />
            <button className="btn btn-dark w-100">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5">
      <h2 className="fw-bold text-primary mb-4 text-center">Manage Projects</h2>
      <div className="table-responsive shadow-lg rounded-4 p-3 bg-white border">
        <table className="table table-hover align-middle">
          <thead className="table-dark">
            <tr>
              <th>Client Name</th>
              <th>Service</th>
              <th>Progress (%)</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {requests.map((req) => (
              <tr key={req._id}>
                <td className="fw-bold">{req.fullName}</td>
                <td><span className="badge bg-info text-dark">{req.serviceType}</span></td>
                <td>
                   {/* min="0" आणि max="100" टाकल्यामुळे मायनस व्हॅल्यू टाकता येणार नाही */}
                   <input 
                      type="number" 
                      id={`progress-${req._id}`} 
                      className="form-control form-control-sm" 
                      defaultValue={req.progress} 
                      min="0" 
                      max="100" 
                      style={{ width: '80px' }} 
                   />
                </td>
                <td>
                  <select id={`status-${req._id}`} className="form-select form-select-sm" defaultValue={req.status}>
                    <option value="Pending">Pending</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                  </select>
                </td>
                <td>
                  <div className="btn-group">
                    <button className="btn btn-success btn-sm" onClick={() => handleUpdate(req._id, document.getElementById(`status-${req._id}`).value, document.getElementById(`progress-${req._id}`).value)}>Update</button>
                    <button className="btn btn-outline-danger btn-sm" onClick={() => handleDelete(req._id)}>Delete</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
